  function isPrime(num) {
    if (num <= 1) return false; // 1 and below are not prime
    if (num <= 3) return true;   // 2 and 3 are prime

    if (num % 2 === 0 || num % 3 === 0) return false; // Divisible by 2 or 3, not prime

